column.value:
{
  "pageDescription": "Sample Processing & Aliquoting - Cassette Workflow",
  "workflowHierarchy": {
    "description": "Histopathology sample processing follows the hierarchy: Specimen → Cassette → Block → Slide",
    "levels": [
      {"level": 1, "name": "Specimen", "description": "Original tissue specimen received", "idField": "specimenId"},
      {"level": 2, "name": "Cassette", "description": "Tissue placed in cassette for processing", "idField": "cassetteId", "sampleType": "Tissue cassette"},
      {"level": 3, "name": "Block", "description": "Processed tissue embedded in paraffin", "idField": "blockId", "sampleType": "Paraffin block"},
      {"level": 4, "name": "Slide", "description": "Sections mounted on glass slide", "idField": "slideId", "sampleType": "Tissue slide"}
    ]
  },
  "dataPoints": {
    "grossExamination": {
      "grossExamDate": {"type": "dateTime", "label": "Gross Examination Date", "required": true},
      "grossExamBy": {"type": "text", "label": "Examined By (Pathologist/Resident)", "required": true},
      "grossDescription": {"type": "textarea", "label": "Gross Description", "required": true},
      "specimenDimensions": {"type": "text", "label": "Specimen Dimensions (cm)"},
      "specimenWeight": {"type": "number", "label": "Specimen Weight (g)"},
      "sectionsSubmitted": {"type": "number", "label": "Number of Sections Submitted", "required": true}
    },
    "cassettingInfo": {
      "cassetteId": {"type": "text", "label": "Cassette ID", "required": true, "description": "Unique identifier for the tissue cassette"},
      "cassetteColor": {"type": "choice", "label": "Cassette Color", "options": ["White", "Blue", "Pink", "Green", "Yellow", "Orange", "Lavender"], "description": "Color coding for specimen type or priority"},
      "cassetteLabel": {"type": "text", "label": "Cassette Label", "description": "Text written/printed on cassette"},
      "tissueOrientation": {"type": "text", "label": "Tissue Orientation", "description": "How tissue is oriented in cassette (ink marks, sutures)"},
      "numberOfCassettes": {"type": "number", "label": "Number of Cassettes", "required": true, "min": 1}
    },
    "processingInfo": {
      "processorId": {"type": "text", "label": "Tissue Processor ID"},
      "processingProtocol": {"type": "choice", "label": "Processing Protocol", "options": ["Standard overnight", "Rapid (biopsy)", "Extended (fatty tissue)", "Decalcification required"]},
      "processingStartTime": {"type": "dateTime", "label": "Processing Start Time"},
      "processingEndTime": {"type": "dateTime", "label": "Processing End Time"},
      "processingTechnician": {"type": "text", "label": "Processing Technician"}
    },
    "embeddingInfo": {
      "blockId": {"type": "text", "label": "Block ID", "required": true, "description": "Unique identifier for the paraffin block"},
      "embeddingDate": {"type": "date", "label": "Embedding Date", "required": true},
      "embeddingTechnician": {"type": "text", "label": "Embedding Technician", "required": true},
      "orientationConfirmed": {"type": "boolean", "label": "Tissue Orientation Confirmed", "required": true}
    },
    "microtomyInfo": {
      "slideId": {"type": "text", "label": "Slide ID", "description": "Unique identifier for the glass slide"},
      "sectionThickness": {"type": "number", "label": "Section Thickness (um)", "default": 4, "min": 1, "max": 10},
      "numberOfSlides": {"type": "number", "label": "Number of Slides Cut"},
      "microtomyTechnician": {"type": "text", "label": "Microtomy Technician"},
      "sectionQuality": {"type": "choice", "label": "Section Quality", "options": ["Good", "Acceptable", "Poor - recut needed"]}
    }
  },
  "childCreationOptions": [
    {"type": "cassette", "label": "Create Cassette from Specimen", "sampleType": "Tissue cassette", "idPrefix": "CAS"},
    {"type": "block", "label": "Create Block from Cassette", "sampleType": "Paraffin block", "idPrefix": "BLK"},
    {"type": "slide", "label": "Create Slide from Block", "sampleType": "Tissue slide", "idPrefix": "SLD"}
  ],
  "systemActions": ["Create cassette child samples", "Create block child samples", "Create slide child samples", "Track parent-child relationships", "Generate cassette/block/slide labels"],
  "nextPage": "Testing, Staining & Microscopy"
}
